+++ b/cmd/opampsupervisor/supervisor/commander/commander.go
@@ -313,6 +313,26 @@ func (c *Commander) IsRunning() bool {
 	return c.running.Load() != 0
 }

+// Reload sends a SIGHUP signal to the Agent process to trigger a configuration reload.
+// This is only effective if the Agent supports SIGHUP-based configuration reloading.
+// Returns an error if the process is not running or if sending the signal fails.
+func (c *Commander) Reload(ctx context.Context) error {
+	if c.running.Load() == 0 {
+		return errors.New("cannot reload: agent process is not running")
+	}
+
+	pid := c.cmd.Process.Pid
+	c.logger.Debug("Reloading agent configuration", zap.Int("pid", pid))
+
+	// Send SIGHUP signal to reload configuration.
+	if err := sendReloadSignal(c.cmd.Process); err != nil {
+		return fmt.Errorf("failed to send reload signal: %w", err)
+	}
+
+	c.logger.Debug("Reload signal sent successfully", zap.Int("pid", pid))
+	return nil
+}
+
 // Stop the Agent process. Sends SIGTERM to the process and wait for up 10 seconds
 // and if the process does not finish kills it forcedly by sending SIGKILL.
 // Returns after the process is terminated.
