func (s *Supervisor) stopAgentApplyConfig() {
	s.telemetrySettings.Logger.Debug("Applying new config to the agent")
	cfgState := s.cfgState.Load().(*configState)

	// Write the new config to disk first
	if err := os.WriteFile(s.agentConfigFilePath(), []byte(cfgState.mergedConfig), 0o600); err != nil {
		s.telemetrySettings.Logger.Error("Failed to write agent config.", zap.Error(err))
		return
	}

	// Try to reload the agent using SIGHUP if it's running
	if s.commander.IsRunning() {
		s.telemetrySettings.Logger.Debug("Attempting to reload agent configuration with SIGHUP")
		err := s.commander.Reload(context.Background())
		if err != nil {
			// If reload is not supported (e.g., on Windows) or fails, fall back to restart
			s.telemetrySettings.Logger.Info("Configuration reload via signal not supported or failed, restarting agent instead", zap.Error(err))
			err = s.commander.Stop(context.Background())
			if err != nil {
				s.telemetrySettings.Logger.Error("Could not stop agent process", zap.Error(err))
			}
		} else {
			s.telemetrySettings.Logger.Debug("Agent configuration reload signal sent successfully")
		}
	}
}

