package main

import (
	"context"
	"fmt"
	"os"
	"os/exec"
	"os/signal"
	"syscall"
	"time"
)

// This is a simple test program that mimics a collector that can handle SIGHUP
func main() {
	// Create a file to track reloads
	reloadCountFile := "/tmp/reload_count.txt"

	// Initialize reload count
	reloadCount := 0
	if err := os.WriteFile(reloadCountFile, []byte("0"), 0644); err != nil {
		fmt.Fprintf(os.Stderr, "Failed to write initial reload count: %v\n", err)
		os.Exit(1)
	}

	// Set up signal handling
	sigChan := make(chan os.Signal, 1)
	signal.Notify(sigChan, syscall.SIGHUP, syscall.SIGTERM, syscall.SIGINT)

	fmt.Println("Test collector started, waiting for signals...")

	ctx, cancel := context.WithCancel(context.Background())
	defer cancel()

	// Simulate the collector running
	go func() {
		ticker := time.NewTicker(100 * time.Millisecond)
		defer ticker.Stop()
		for {
			select {
			case <-ctx.Done():
				return
			case <-ticker.C:
				// Simulate collector doing work
			}
		}
	}()

	// Wait for signals
	for {
		sig := <-sigChan
		switch sig {
		case syscall.SIGHUP:
			// Simulate configuration reload
			reloadCount++
			fmt.Printf("Received SIGHUP, reloading configuration (count: %d)\n", reloadCount)
			if err := os.WriteFile(reloadCountFile, []byte(fmt.Sprintf("%d", reloadCount)), 0644); err != nil {
				fmt.Fprintf(os.Stderr, "Failed to write reload count: %v\n", err)
			}
		case syscall.SIGTERM, syscall.SIGINT:
			fmt.Println("Received shutdown signal, exiting...")
			cancel()
			os.Exit(0)
		}
	}
}

