	"github.com/stretchr/testify/require"
	"go.uber.org/zap"

	"github.com/open-telemetry/opentelemetry-collector-contrib/cmd/opampsupervisor/supervisor/config"
)

func TestCommanderReload(t *testing.T) {
	// Build the test collector binary
	testBinaryPath := filepath.Join(t.TempDir(), "test_collector")

	// Build the test binary
	cmd := exec.Command("go", "build", "-o", testBinaryPath, "/testbed/test_sighup_reload.go")
	output, err := cmd.CombinedOutput()
	require.NoError(t, err, "Failed to build test binary: %s", string(output))

	// Create a temporary directory for logs
	logsDir := t.TempDir()

	// Create the commander
	logger := zap.NewNop()
	cfg := config.Agent{
		Executable: testBinaryPath,
	}

	commander, err := NewCommander(logger, logsDir, cfg)
	require.NoError(t, err)

	// Start the test collector
	ctx := context.Background()
	err = commander.Start(ctx)
	require.NoError(t, err)
	require.True(t, commander.IsRunning())

	// Wait for the process to be fully started
	time.Sleep(500 * time.Millisecond)

	// Test 1: Reload should succeed when process is running
	err = commander.Reload(ctx)
	assert.NoError(t, err, "Reload should succeed when process is running")

	// Wait a bit for the signal to be processed
	time.Sleep(500 * time.Millisecond)

	// Verify that the reload count was incremented
	reloadCountFile := "/tmp/reload_count.txt"
	content, err := os.ReadFile(reloadCountFile)
	require.NoError(t, err, "Should be able to read reload count file")
	assert.Equal(t, "1", string(content), "Reload count should be 1 after first reload")

	// Test 2: Send another reload signal
	err = commander.Reload(ctx)
	assert.NoError(t, err, "Second reload should also succeed")

	// Wait for signal processing
	time.Sleep(500 * time.Millisecond)

	// Verify reload count increased
	content, err = os.ReadFile(reloadCountFile)
	require.NoError(t, err, "Should be able to read reload count file after second reload")
	assert.Equal(t, "2", string(content), "Reload count should be 2 after second reload")

	// Test 3: Stop the process
	err = commander.Stop(ctx)
	require.NoError(t, err)
	assert.False(t, commander.IsRunning())

	// Test 4: Reload should fail when process is not running
	err = commander.Reload(ctx)
	assert.Error(t, err, "Reload should fail when process is not running")
	assert.Contains(t, err.Error(), "not running", "Error message should indicate process is not running")

	// Clean up the reload count file
	os.Remove(reloadCountFile)
}

func TestCommanderReloadNotStarted(t *testing.T) {
	// Create a commander but don't start it
	logger := zap.NewNop()
	cfg := config.Agent{
		Executable: "/bin/echo",
	}

	logsDir := t.TempDir()
	commander, err := NewCommander(logger, logsDir, cfg)
	require.NoError(t, err)

	// Test: Reload should fail when process was never started
	ctx := context.Background()
	err = commander.Reload(ctx)
	assert.Error(t, err, "Reload should fail when process was never started")
	assert.Contains(t, err.Error(), "not running", "Error message should indicate process is not running")
}

