// This is a standalone test to verify SIGHUP reload functionality
func main() {
	// Build the test collector binary
	testBinaryPath := filepath.Join(os.TempDir(), "test_collector_reload")

	// Build the test binary
	fmt.Println("Building test collector binary...")
	cmd := exec.Command("go", "build", "-o", testBinaryPath, "/testbed/test_sighup_reload.go")
	output, err := cmd.CombinedOutput()
	if err != nil {
		fmt.Fprintf(os.Stderr, "Failed to build test binary: %v\nOutput: %s\n", err, string(output))
		os.Exit(1)
	}
	defer os.Remove(testBinaryPath)

	// Start the test collector
	fmt.Println("Starting test collector...")
	ctx := context.Background()
	testCmd := exec.CommandContext(ctx, testBinaryPath)
	testCmd.Stdout = os.Stdout
	testCmd.Stderr = os.Stderr

	err = testCmd.Start()
	if err != nil {
		fmt.Fprintf(os.Stderr, "Failed to start test collector: %v\n", err)
		os.Exit(1)
	}

	pid := testCmd.Process.Pid
	fmt.Printf("Test collector started with PID: %d\n", pid)

	// Wait for the process to be fully started
	time.Sleep(1 * time.Second)

	// Send SIGHUP signal
	fmt.Println("Sending SIGHUP signal...")
	err = testCmd.Process.Signal(syscall.SIGHUP)
	if err != nil {
		fmt.Fprintf(os.Stderr, "Failed to send SIGHUP: %v\n", err)
		testCmd.Process.Kill()
		os.Exit(1)
	}

	// Wait for signal processing
	time.Sleep(1 * time.Second)

	// Verify that the reload count was incremented
	reloadCountFile := "/tmp/reload_count.txt"
	content, err := os.ReadFile(reloadCountFile)
	if err != nil {
		fmt.Fprintf(os.Stderr, "Failed to read reload count file: %v\n", err)
		testCmd.Process.Kill()
		os.Exit(1)
	}

	if string(content) != "1" {
		fmt.Fprintf(os.Stderr, "Expected reload count to be 1, got: %s\n", string(content))
		testCmd.Process.Kill()
		os.Exit(1)
	}

	fmt.Println("✓ First reload successful")

	// Send another SIGHUP signal
	fmt.Println("Sending second SIGHUP signal...")
	err = testCmd.Process.Signal(syscall.SIGHUP)
	if err != nil {
		fmt.Fprintf(os.Stderr, "Failed to send second SIGHUP: %v\n", err)
		testCmd.Process.Kill()
		os.Exit(1)
	}

	// Wait for signal processing
	time.Sleep(1 * time.Second)

	// Verify reload count increased
	content, err = os.ReadFile(reloadCountFile)
