		os.Exit(1)
	}
	defer os.Remove(testBinaryPath)

	// Create a temporary directory for logs
	logsDir, err := os.MkdirTemp("", "supervisor_test_logs")
	if err != nil {
		fmt.Fprintf(os.Stderr, "Failed to create logs directory: %v\n", err)
		os.Exit(1)
	}
	defer os.RemoveAll(logsDir)

	// Create the commander
	logger, err := zap.NewDevelopment()
	if err != nil {
		fmt.Fprintf(os.Stderr, "Failed to create logger: %v\n", err)
		os.Exit(1)
	}

	cfg := config.Agent{
		Executable: testBinaryPath,
	}

	cmd1, err := commander.NewCommander(logger, logsDir, cfg)
	if err != nil {
		fmt.Fprintf(os.Stderr, "Failed to create commander: %v\n", err)
		os.Exit(1)
	}

	// Test 1: Start the collector
	fmt.Println("\n=== Test 1: Starting collector ===")
	ctx := context.Background()
	err = cmd1.Start(ctx)
	if err != nil {
		fmt.Fprintf(os.Stderr, "Failed to start collector: %v\n", err)
		os.Exit(1)
	}

	if !cmd1.IsRunning() {
		fmt.Fprintf(os.Stderr, "Collector should be running but IsRunning() returned false\n")
		os.Exit(1)
	}

	originalPID := cmd1.Pid()
	fmt.Printf("✓ Collector started with PID: %d\n", originalPID)

	// Wait for the process to be fully started
	time.Sleep(1 * time.Second)

	// Test 2: Reload configuration (simulate supervisor behavior)
	fmt.Println("\n=== Test 2: Reloading configuration with SIGHUP ===")

	// Write new config to disk (simulating what supervisor does)
	configPath := filepath.Join(logsDir, "test_config.yaml")
	err = os.WriteFile(configPath, []byte("# Updated config v1"), 0600)
	if err != nil {
		fmt.Fprintf(os.Stderr, "Failed to write config file: %v\n", err)
		cmd1.Stop(ctx)
		os.Exit(1)
	}

	// Call Reload (what supervisor now does instead of Stop+Start)
	err = cmd1.Reload(ctx)
	if err != nil {
		fmt.Fprintf(os.Stderr, "Failed to reload: %v\n", err)
		cmd1.Stop(ctx)
		os.Exit(1)
	}

	time.Sleep(1 * time.Second)

	// Verify PID hasn't changed
	currentPID := cmd1.Pid()
	if currentPID != originalPID {
		fmt.Fprintf(os.Stderr, "ERROR: PID changed from %d to %d after reload!\n", originalPID, currentPID)
		cmd1.Stop(ctx)
		os.Exit(1)
	}

	fmt.Printf("✓ Configuration reloaded, PID unchanged: %d\n", currentPID)

	// Verify reload happened
	reloadCountFile := "/tmp/reload_count.txt"
	content, err := os.ReadFile(reloadCountFile)
	if err != nil {
		fmt.Fprintf(os.Stderr, "Failed to read reload count file: %v\n", err)
		cmd1.Stop(ctx)
		os.Exit(1)
	}

	if string(content) != "1" {
		fmt.Fprintf(os.Stderr, "Expected reload count to be 1, got: %s\n", string(content))
		cmd1.Stop(ctx)
		os.Exit(1)
	}

	fmt.Println("✓ Configuration reload confirmed")

	// Test 3: Multiple reloads
	fmt.Println("\n=== Test 3: Multiple configuration reloads ===")
	for i := 2; i <= 3; i++ {
		// Write new config
		err = os.WriteFile(configPath, []byte(fmt.Sprintf("# Updated config v%d", i)), 0600)
		if err != nil {
			fmt.Fprintf(os.Stderr, "Failed to write config file: %v\n", err)
			cmd1.Stop(ctx)
			os.Exit(1)
		}

		// Reload
		err = cmd1.Reload(ctx)
		if err != nil {
			fmt.Fprintf(os.Stderr, "Failed to reload (iteration %d): %v\n", i, err)
			cmd1.Stop(ctx)
			os.Exit(1)
		}

		time.Sleep(500 * time.Millisecond)

		// Verify PID hasn't changed
		currentPID = cmd1.Pid()
		if currentPID != originalPID {
			fmt.Fprintf(os.Stderr, "ERROR: PID changed from %d to %d after reload %d!\n", originalPID, currentPID, i)
			cmd1.Stop(ctx)
			os.Exit(1)
		}

		// Verify reload count
		content, err = os.ReadFile(reloadCountFile)
		if err != nil {
			fmt.Fprintf(os.Stderr, "Failed to read reload count file: %v\n", err)
			cmd1.Stop(ctx)
			os.Exit(1)
		}

		expectedCount := fmt.Sprintf("%d", i)
		if string(content) != expectedCount {
			fmt.Fprintf(os.Stderr, "Expected reload count to be %s, got: %s\n", expectedCount, string(content))
			cmd1.Stop(ctx)
			os.Exit(1)
		}

		fmt.Printf("✓ Reload %d successful, PID still: %d\n", i, currentPID)
	}

	// Test 4: Stop the collector
	fmt.Println("\n=== Test 4: Stopping collector ===")
	err = cmd1.Stop(ctx)
	if err != nil {
		fmt.Fprintf(os.Stderr, "Failed to stop collector: %v\n", err)
		os.Exit(1)
	}

	if cmd1.IsRunning() {
		fmt.Fprintf(os.Stderr, "Collector should not be running but IsRunning() returned true\n")
		os.Exit(1)
	}

	fmt.Println("✓ Collector stopped successfully")

	// Test 5: Reload should fail when collector is not running
	fmt.Println("\n=== Test 5: Reload should fail when collector is not running ===")
	err = cmd1.Reload(ctx)
	if err == nil {
		fmt.Fprintf(os.Stderr, "Reload should have failed when collector is not running\n")
		os.Exit(1)
	}

	if !strings.Contains(err.Error(), "not running") {
		fmt.Fprintf(os.Stderr, "Error message should indicate process is not running, got: %v\n", err)
		os.Exit(1)
	}

	fmt.Println("✓ Reload correctly failed when collector not running")

	// Clean up
	os.Remove(reloadCountFile)

	fmt.Println("\n✓✓✓ All integration tests passed!")
	fmt.Println("✓✓✓ Commander correctly uses SIGHUP for configuration reload!")
	fmt.Println("✓✓✓ PID remains stable across multiple reloads!")
}

